    $InputObject | Remove-WindowsCapability -Online -ErrorAction 'Continue';
  }
};
$type = 'Capability';
$logfile = 'C:\Windows\Setup\Scripts\RemoveCapabilities.log';
& {
	$installed = & $getCommand;
	foreach( $selector in $selectors ) {
		$result = [ordered] @{
			Selector = $selector;
		};
		$found = $installed | Where-Object -FilterScript $filterCommand;
		if( $found ) {
			$result.Output = $found | & $removeCommand;
			if( $? ) {
				$result.Message = "$type removed.";
			} else {
				$result.Message = "$type not removed.";
				$result.Error = $Error[0];
			}
		} else {
			$result.Message = "$type not installed.";
		}
		$result | ConvertTo-Json -Depth 3 -Compress;
	}
} *>&1 | Out-String -Width 1KB -Stream >> $logfile;

Add-Type -TypeDefinition '
	using System.Drawing;
	using System.Runtime.InteropServices;
	
	public static class WallpaperSetter {
		[DllImport("user32.dll")]
		private static extern bool SetSysColors(
			int cElements, 
			int[] lpaElements,
			int[] lpaRgbValues
		);

		[DllImport("user32.dll")]
		private static extern bool SystemParametersInfo(
			uint uiAction,
			uint uiParam,
			string pvParam,
			uint fWinIni
		);

		public static void SetDesktopBackground(Color color) {
			SystemParametersInfo(20, 0, "", 0);
			SetSysColors(1, new int[] { 1 }, new int[] { ColorTranslator.ToWin32(color) });
		}

		public static void SetDesktopImage(string file) {
			SystemParametersInfo(20, 0, file, 0);
		}
	}
' -ReferencedAssemblies 'System.Drawing';

function Set-WallpaperColor {
	param(
		[string]
		$HtmlColor
	);

	$color = [System.Drawing.ColorTranslator]::FromHtml( $HtmlColor );
	[WallpaperSetter]::SetDesktopBackground( $color );
	Set-ItemProperty -Path 'Registry::HKCU\Software\Microsoft\Windows\CurrentVersion\Explorer\Wallpapers' -Name 'BackgroundType' -Type 'DWord' -Value 1 -Force;
	Set-ItemProperty -Path 'Registry::HKCU\Control Panel\Desktop' -Name 'WallPaper' -Type 'String' -Value '' -Force;
	Set-ItemProperty -Path 'Registry::HKCU\Control Panel\Colors' -Name 'Background' -Type 'String' -Value "$($color.R) $($color.G) $($color.B)" -Force;
}

function Set-WallpaperImage {
	param(
		[string]
		$LiteralPath
	);

	if( $LiteralPath | Test-Path ) {
		[WallpaperSetter]::SetDesktopImage( $LiteralPath );
		Set-ItemProperty -Path 'Registry::HKCU\Software\Microsoft\Windows\CurrentVersion\Explorer\Wallpapers' -Name 'BackgroundType' -Type 'DWord' -Value 0 -Force;
		Set-ItemProperty -Path 'Registry::HKCU\Control Panel\Desktop' -Name 'WallPaper' -Type 'String' -Value $LiteralPath -Force;
	} else {
		"Cannot use '$LiteralPath' as a desktop wallpaper because that file does not exist.";
	}
}
Set-WallpaperImage -LiteralPath 'C:\Windows\Setup\Scripts\Wallpaper';

#Requires -Version 5.1 <# P0-Main.ps1 Orquestrador de instalação/provisionamento - Senhor Contabil
O que este script faz: 1. Verifica se está rodando como Administrador. 2. Baixa cada script (P1..P10) de um COMMIT FIXO do GitHub (nunca da branch main), para que uma alteração futura no repositório não afete instalações já validadas. 3. Confere o hash SHA256 de cada arquivo baixado contra o manifesto abaixo. Se o hash não bater, o script PARA e avisa (não executa nada baixado sem conferência). 4. Executa cada etapa (P1..P10) em sequência, registrando sucesso/falha em log.
Como atualizar quando você mudar algo no repositório: 1. Faça o commit normalmente no GitHub. 2. Pegue o SHA do novo commit (na página do commit, ou "git log -1 --format=%H"). 3. Rode a seção "GERAR MANIFESTO" abaixo (uma vez, localmente, a partir de arquivos que você já revisou) para calcular os novos hashes. 4. Cole o novo SHA em $CommitSha e os novos hashes no $Manifest. Isso é intencional: a atualização exige uma ação manual sua, não é automática. #>
$ErrorActionPreference = 'Stop'
# ============================================================ # CONFIGURAÇÃO — AJUSTE AQUI # ============================================================
$RepoOwner = "antoniosilva-coder" $RepoName = "Contabil_Default"
# Cole aqui o SHA completo (40 caracteres) do commit que você revisou e aprova. # NUNCA use "main" aqui — isso anularia a proteção contra alteração posterior do repo. $CommitSha = "COLOQUE_AQUI_O_SHA_DO_COMMIT_APROVADO"
# Hash SHA256 esperado de cada arquivo, no commit acima. # Gere com: Get-FileHash -Algorithm SHA256 -Path .\P1-Energia.ps1 # (rode isso localmente, a partir da cópia que você já leu e aprovou, e cole o resultado abaixo) $Manifest = [ordered]@{ "P1-Energia.ps1" = "COLOQUE_O_HASH_SHA256_AQUI" "P2-Ninite.ps1" = "COLOQUE_O_HASH_SHA256_AQUI" "Ninite-SenhorContabil.exe" = "COLOQUE_O_HASH_SHA256_AQUI" "P3-WindowsUpdate.ps1" = "COLOQUE_O_HASH_SHA256_AQUI" "P4-RustDesk.ps1" = "COLOQUE_O_HASH_SHA256_AQUI" "P5-NetFramework35.ps1" = "COLOQUE_O_HASH_SHA256_AQUI" "P6-Winget.ps1" = "COLOQUE_O_HASH_SHA256_AQUI" "P7-Defender.ps1" = "COLOQUE_O_HASH_SHA256_AQUI" "P8-TimeSync.ps1" = "COLOQUE_O_HASH_SHA256_AQUI" "P9-CleanTemp.ps1" = "COLOQUE_O_HASH_SHA256_AQUI" "P10-Finalizacao.ps1" = "COLOQUE_O_HASH_SHA256_AQUI" }
# Ordem de execução dos scripts .ps1 (o .exe do Ninite é baixado mas não "executado" por aqui; # quem o executa é o próprio P2-Ninite.ps1) $StepsOrder = @( "P1-Energia.ps1", "P2-Ninite.ps1", "P8-TimeSync.ps1", # movido para mais cedo: hora errada pode quebrar downloads HTTPS "P3-WindowsUpdate.ps1", "P4-RustDesk.ps1", "P5-NetFramework35.ps1", "P6-Winget.ps1", "P7-Defender.ps1", "P9-CleanTemp.ps1", "P10-Finalizacao.ps1" )
$WorkDir = "C:\ProgramData\SenhorContabil" $LogFile = Join-Path $WorkDir "status.log" $DownloadDir = Join-Path $WorkDir "scripts"
# ============================================================ # 1. CHECAGEM DE ADMINISTRADOR # ============================================================
$isAdmin = ([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltinRole]::Administrator) if (-not $isAdmin) { Write-Error "Este script precisa ser executado como Administrador. Abra o PowerShell como Administrador e rode novamente." exit 1 }
if ($CommitSha -eq "COLOQUE_AQUI_O_SHA_DO_COMMIT_APROVADO") { Write-Error "Configuração incompleta: defina `$CommitSha com o SHA do commit aprovado antes de rodar em produção." exit 1 }
New-Item -ItemType Directory -Path $WorkDir -Force | Out-Null New-Item -ItemType Directory -Path $DownloadDir -Force | Out-Null
function Write-Log { param([string]$Step, [string]$Status, [string]$Detail = "") $line = "{0}`t{1}`t{2}`t{3}" -f (Get-Date -Format "yyyy-MM-dd HH:mm:ss"), $Step, $Status, $Detail Add-Content -Path $LogFile -Value $line }
# ============================================================ # 2. DOWNLOAD + VERIFICAÇÃO DE HASH (commit fixo) # ============================================================
function Get-VerifiedFile { param( [Parameter(Mandatory)][string]$FileName )
$expectedHash = $Manifest[$FileName] if (-not $expectedHash -or $expectedHash -eq "COLOQUE_O_HASH_SHA256_AQUI") { throw "Hash não configurado para '$FileName' no manifesto. Gere com Get-FileHash e preencha `$Manifest antes de rodar em produção." }
$url = "https://raw.githubusercontent.com/$RepoOwner/$RepoName/$CommitSha/$FileName" $destination = Join-Path $DownloadDir $FileName
Invoke-WebRequest -Uri $url -OutFile $destination -UseBasicParsing
$actualHash = (Get-FileHash -Algorithm SHA256 -Path $destination).Hash
if ($actualHash -ne $expectedHash) { Remove-Item $destination -Force -ErrorAction SilentlyContinue throw "Hash divergente para '$FileName'. Esperado: $expectedHash | Obtido: $actualHash. O arquivo remoto pode ter sido alterado — download bloqueado." }
return $destination }
# ============================================================ # 3. EXECUÇÃO DAS ETAPAS # ============================================================
Write-Host "=========================================" Write-Host " Senhor Contabil - Instalacao Automatica " Write-Host "=========================================" Write-Host "Commit fixo em uso: $CommitSha" Write-Host ""
Write-Log -Step "P0-Main" -Status "INICIO" -Detail "Commit=$CommitSha"
foreach ($step in $StepsOrder) { Write-Host "--- Executando $step ---" try { # Baixa e confere o hash do script em si $scriptPath = Get-VerifiedFile -FileName $step
# P2 também precisa do instalador do Ninite: baixa e confere antes de rodar if ($step -eq "P2-Ninite.ps1") { Get-VerifiedFile -FileName "Ninite-SenhorContabil.exe" | Out-Null }
& $scriptPath Write-Log -Step $step -Status "OK" Write-Host "[OK] $step concluido." } catch { Write-Log -Step $step -Status "FALHA" -Detail $_.Exception.Message Write-Host "[FALHA] $step : $($_.Exception.Message)" -ForegroundColor Red # Continua para as próximas etapas mesmo se uma falhar, # para que o P10 final mostre o resumo real de tudo que rodou ou não. } }
Write-Log -Step "P0-Main" -Status "FIM" Write-Host "" Write-Host "Instalacao finalizada. Veja o resumo acima (executado pelo P10) e o log completo em:" Write-Host $LogFile

